frame_eqs:
warp = 0;

volume = 0.3*(bass+mid);
beatrate = equal(beatrate,0) + (1-equal(beatrate,0))*(below(volume,0.01) + (1-below(volume,0.01))*beatrate);
lastbeat = lastbeat + equal(lastbeat,0)*time;
meanbass_att = 0.1*(meanbass_att*9 + bass_att);
peakbass_att = max(bass_att,peakbass_att);
beat = above(volume,0.8)*below(peakbass_att - bass_att, 0.05*peakbass_att)*above(time - lastbeat, 0.1 + 0.5*(beatrate - 0.1));
beatrate = max(if(beat,if(below(time-lastbeat,2*beatrate),0.1*(beatrate*9 + time - lastbeat),beatrate),beatrate),0.1);
peakbass_att = beat*bass_att + (1-beat)*peakbass_att*(above(time - lastbeat, 2*beatrate)*0.95 + (1-above(time - lastbeat, 2*beatrate))*0.995);
lastbeat = beat*time + (1-beat)*lastbeat;
peakbass_att = max(peakbass_att,1.1*meanbass_att);
beatcount = beatcount + beat*if(above(beatcount,int(rand(3))+2),1-beatcount,1);

red=if(equal(beatcount,beat),int(rand(2)),red);
green=if(equal(beatcount,beat),int(rand(2)),green);
blue=if(equal(beatcount,beat),int(rand(2)),blue);
white = below(red+blue+green,3);
red = red*white;
blue = blue*white;
green = green*white;

change=equal(beatcount,beat);
orient=if(change,int(rand(4)),orient);
echo_orient = orient;

ib_a=if(change,1,0.005);
ob_a=if(change,1,0.005);
ib_r = red;
ib_g = green;
ib_b = blue;
ob_r = red;
ob_g = green;
ob_b = blue;

xshift = if(change,if(equal(abs(orient-1),1),(int(rand(50))-25)*0.0001,0),xshift);
yshift = if(change,if(below(orient,2),(int(rand(50))-25)*0.0001,0),yshift);
rotate = if(change,if(equal(abs(orient-1.5),1.5),(int(rand(50))-25)*0.0002,0),rotate);
dx = xshift;
dy = yshift;
rot = rotate;

wave_0_per_point:
ma=ma+(3.1415*.01*bass);
ma=ma-(3.1415*.01*treb);

mx=mx+(.0002*cos(ma));
my=my+(.0002*sin(ma));

wrap = 0;
wrap = if(above(mx,.99),1,wrap);
wrap = if(above(my,.99),1,wrap);
wrap = if(below(mx,.01),1,wrap);
wrap = if(below(my,.01),1,wrap);
mx=if(above(mx,1),if(wrap,(1.01-mx),mx),mx);
my=if(above(my,1),if(wrap,(1.01-my),my),my);
mx=if(below(mx,0),if(wrap,(.99+mx),mx),mx);
my=if(below(my,0),if(wrap,(.99+my),my),my);

r=0|0.7*bass_att;
g=0|0.6*treb_att;
b=0|0.5*mid_att;

x=mx;
y=my;

